export const code = async (inputs) => {
  const regions = (typeof inputs.regions_array === 'string' 
    ? JSON.parse(inputs.regions_array) 
    : inputs.regions_array) as any[];

  const subscriptions = (typeof inputs.subscriptions_array === 'string' 
    ? JSON.parse(inputs.subscriptions_array) 
    : inputs.subscriptions_array) as any[];

  return { regions, subscriptions };
};

export const code = async (inputs) => {
  return inputs.subscriptions && inputs.subscriptions.length > 5;
};

export const code = async (inputs) => {
  const prices = inputs.lastDaysPrices;

  if (!prices || prices.length === 0) {
    return { average: 0, currency: null };
  }

  const total = prices.reduce((sum, [price]) => sum + price, 0);
  const average = total / prices.length;

  return {
    average,
  };
};

export const code = async (inputs) => {
  const grouped = {};

  for (const [cost, date, resourceId, currency] of inputs.costs) {
    if (!grouped[resourceId]) {
      grouped[resourceId] = {
        resourceId,
        currency,
        datesWithCosts: []
      };
    }

    grouped[resourceId].datesWithCosts.push([cost, date]);
  }

  return Object.values(grouped);
};

export const code = async (inputs) => {
  const items = inputs.pricingItems || [];

  const today = new Date();
  const dateKey = Number(
    `${today.getUTCFullYear()}${String(today.getUTCMonth() + 1).padStart(2, "0")}${String(today.getUTCDate()).padStart(2, "0")}`
  );

  return items
    .map(item => {
      const parsedItem = typeof item === "string" ? JSON.parse(item) : item;

      return {
        resourceId: parsedItem.resourceId,
        currency: parsedItem.currency || "USD",
        datesWithCosts: [
          [
            parsedItem.dailyPricing || 0,
            dateKey
          ]
        ]
      };
    })
    .filter(item => item.resourceId);
};

export const code = async (inputs) => {
  const plans = Array.isArray(inputs.servicePlans) ? inputs.servicePlans : [];

  const counts = plans.reduce((acc, id) => {
    if (typeof id !== "string" || !id.trim()) return acc;
    const key = id.trim();
    acc[key] = (acc[key] || 0) + 1;
    return acc;
  }, {});

  return Object.entries(counts).map(([appServicePlanId, unusedApps]) => ({
    appServicePlanId,
    unusedApps,
  }));
};

export const code = async (inputs) => {
  const { appServicePlan, priceList } = inputs;

  const items = Array.isArray(priceList)
    ? priceList
    : Array.isArray(priceList?.Items)
      ? priceList.Items
      : [];

  const resourceId =
    appServicePlan?.id ||
    appServicePlan?.resourceMetadata?.resourceId ||
    null;

  const sku = appServicePlan?.sku || {};
  const skuName = sku.name || sku.size || null;

  const isLinux =
    appServicePlan?.kind?.toLowerCase().includes("linux") ||
    appServicePlan?.reserved === true;

  const normalize = (value) =>
    String(value || "")
      .toLowerCase()
      .replace(/[_-]/g, "")
      .replace(/\s+/g, "")
      .trim();

  const normalizeSku = (value) =>
    normalize(value)
      .replace("v", "")
      .replace("app", "");

  const expectedSku = normalizeSku(skuName);

  if (!skuName) {
    return {
      resourceId,
      dailyPricing: 0,
      currency: "USD"
    };
  }

  const priceItem = items.find((p) => {
    if (p.type !== "Consumption") return false;
    if (p.serviceName !== "Azure App Service") return false;
    if (p.unitOfMeasure !== "1 Hour") return false;

    const priceSku = normalizeSku(p.skuName);
    const meterName = normalizeSku(p.meterName);
    const productName = String(p.productName || "").toLowerCase();

    if (priceSku !== expectedSku && !meterName.includes(expectedSku)) {
      return false;
    }

    if (isLinux && !productName.includes("linux")) {
      return false;
    }

    if (!isLinux && productName.includes("linux")) {
      return false;
    }

    if (
      productName.includes("ssl") ||
      productName.includes("domain") ||
      productName.includes("stamp") ||
      productName.includes("isolated") ||
      p.skuName === "ASIP" ||
      p.skuName === "Front End"
    ) {
      return false;
    }

    return true;
  });

  if (!priceItem || typeof priceItem.retailPrice !== "number") {
    return {
      resourceId,
      dailyPricing: 0,
      currency: "USD"
    };
  }

  const workerCount = Number(
    appServicePlan?.sku?.capacity ||
    appServicePlan?.properties?.numberOfWorkers ||
    appServicePlan?.numberOfWorkers ||
    1
  );

  return {
    resourceId,
    dailyPricing: priceItem.retailPrice * 24 * workerCount,
    currency: priceItem.currencyCode || "USD"
  };
};

export const code = async (inputs) => {
  const timeseries = inputs?.requests?.timeseries;
  if (!Array.isArray(timeseries)) return 0;

  return timeseries.reduce((sum, series) => {
    if (!Array.isArray(series?.data)) return sum;

    return sum + series.data.reduce((innerSum, point) => {
      return innerSum + (typeof point?.total === "number" ? point.total : 0);
    }, 0);
  }, 0);
};

